do $$ begin create type public.tag_sensitivity as enum ('low','medium','high'); exception when duplicate_object then null; end $$;
create table public.universes(id uuid primary key,slug text not null unique check(slug~'^[a-z0-9-]+$'),name text not null unique,description text not null default '',icon_key text not null,display_order smallint not null unique check(display_order>0),is_active boolean not null default true,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create trigger universes_set_updated_at before update on public.universes for each row execute function public.set_updated_at();
alter table public.categories drop constraint categories_display_order_key;
alter table public.categories add column universe_id uuid references public.universes(id) on delete restrict,add column icon_key text;
alter table public.tags add column slug text,add column description text not null default '',add column sensitivity public.tag_sensitivity,add column is_active boolean not null default true,add column is_featured boolean not null default false,add column updated_at timestamptz not null default now();
create trigger tags_set_updated_at before update on public.tags for each row execute function public.set_updated_at();
create table public.category_tags(category_id uuid not null references public.categories(id) on delete cascade,tag_id uuid not null references public.tags(id) on delete cascade,display_order smallint not null check(display_order>0),is_featured boolean not null default false,created_at timestamptz not null default now(),primary key(category_id,tag_id),unique(category_id,display_order));
do $$ declare profiles_before bigint;auth_before bigint;roles_before jsonb;begin
select count(*) into profiles_before from public.profiles;select count(*) into auth_before from auth.users;select jsonb_object_agg(role,total) into roles_before from(select role::text role,count(*) total from public.profiles group by role)x;
delete from public.audit_log where target_type in('question','comment','sponsor_campaign') or action in('moderate_report','create_sponsor_campaign','set_sponsor_campaign_status');delete from public.moderation_actions;delete from public.moderation_cases;delete from public.sponsor_campaigns;delete from public.reports;delete from public.comment_upvotes;delete from public.comments;delete from public.votes;delete from public.question_duplicate_reviews;delete from public.question_follows;delete from public.question_upvotes;delete from public.category_follows;delete from public.interaction_events where question_id is not null or category_id is not null;delete from public.feed_impressions;delete from public.question_metrics_daily;delete from public.question_tags;delete from public.question_options;update public.questions set previous_wave_id=null where previous_wave_id is not null;delete from public.questions;delete from public.question_series;delete from public.categories;delete from public.tags;
if(select count(*) from public.universes where is_active)<>7 or(select count(*) from public.categories where is_active)<>30 then raise exception 'taxonomy_count_invalid';end if;if exists(select 1 from public.questions)or exists(select 1 from public.votes)or exists(select 1 from public.comments)then raise exception 'editorial_data_not_empty';end if;if(select count(*) from public.profiles)<>profiles_before or(select count(*) from auth.users)<>auth_before then raise exception 'identity_count_changed';end if;if(select jsonb_object_agg(role,total)from(select role::text role,count(*)total from public.profiles group by role)x)is distinct from roles_before then raise exception 'role_count_changed';end if;end $$;
alter table public.categories alter column universe_id set not null,alter column icon_key set not null,add constraint categories_universe_display_order_key unique(universe_id,display_order);
alter table public.tags alter column slug set not null,alter column sensitivity set not null,add constraint tags_slug_key unique(slug),add constraint tags_slug_format check(slug~'^[a-z0-9-]+$');
create function public.enforce_controlled_tag_insert()returns trigger language plpgsql security definer set search_path='' as $$begin if auth.role()<>'service_role' and not exists(select 1 from public.tags where normalized_name=new.normalized_name and is_active)then raise exception 'tag_not_allowed' using errcode='P0001';end if;return new;end$$;
create trigger tags_controlled_insert before insert on public.tags for each row execute function public.enforce_controlled_tag_insert();
create function public.enforce_category_tag_assignment()returns trigger language plpgsql security definer set search_path='' as $$begin if not exists(select 1 from public.questions q join public.category_tags ct on ct.category_id=q.category_id and ct.tag_id=new.tag_id join public.tags t on t.id=ct.tag_id and t.is_active where q.id=new.question_id)then raise exception 'tag_not_allowed_for_category' using errcode='P0001';end if;return new;end$$;
create trigger question_tags_controlled before insert or update on public.question_tags for each row execute function public.enforce_category_tag_assignment();
alter table public.universes enable row level security;alter table public.category_tags enable row level security;
create policy universes_select_active on public.universes for select to authenticated using(is_active and public.is_active_user());create policy category_tags_select_active on public.category_tags for select to authenticated using(public.is_active_user() and exists(select 1 from public.categories c join public.tags t on t.id=tag_id where c.id=category_id and c.is_active and t.is_active));
revoke all on public.universes,public.category_tags from anon,authenticated;grant select on public.universes,public.category_tags to authenticated;